// // This module controls the fan speed based on temperature readings. It outputs a 2-bit signal representing the fan speed, with low speed (00) for temperatures from 0 to 5, medium speed (01) for temperatures from 6 to 10, and high speed (10) for temperatures from 11 to 15.
module fan_speed_controller(
    input wire clk,
    input wire reset,
    input wire [3:0] temperature,
    output reg [1:0] fan_speed
);

    // Fan speed states
    localparam LOW = 2'b00;
    localparam MEDIUM = 2'b01;
    localparam HIGH = 2'b10;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            fan_speed <= LOW; // Default to low speed on reset
        end else begin
            if (temperature <= 4'd5) begin
                fan_speed <= LOW;
            end else if (temperature <= 4'd10) begin
                fan_speed <= MEDIUM;
            end else begin
                fan_speed <= HIGH;
            end
        end
    end
endmodule
